+/**
+ * Creates a recursive schema.
+ *
+ * @param wrapped The schema containing recursive placeholders.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(wrapped: TWrapped): RecursiveSchema<TWrapped> {
+  const schema = {
+    kind: 'schema',
+    type: 'recursive',
+    reference: recursive,
+    expects: wrapped.expects,
+    async: false,
+    wrapped,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset, config) {
+      return resolved['~run'](dataset, config);
+    },
+  } as RecursiveSchema<TWrapped>;
+  const resolved = _replaceRecur(wrapped, schema);
+  return schema;
+}
+
+/**
+ * Recursive schema placeholder.
+ */
+export const Recur: Recur = {
+  kind: 'schema',
+  type: 'recur',
+  reference: recursive,
+  expects: 'unknown',
+  async: false,
+  get '~standard'() {
+    return _getStandardProps(this);
+  },
+  '~run'() {
+    throw new TypeError('Recur must be wrapped with recursive().');
+  },
+};
+
+/**
+ * Replaces placeholders in a schema clone.
+ */
+export function _replaceRecur<TValue>(value: TValue, recur: unknown): TValue {
+  if (value === Recur) {
+    return recur as TValue;
+  }
+  if (Array.isArray(value)) {
+    return value.map((item) => _replaceRecur(item, recur)) as TValue;
+  }
+  if (value && typeof value === 'object') {
+    const clone = Object.create(Object.getPrototypeOf(value));
+    for (const key of Reflect.ownKeys(value)) {
+      const descriptor = Object.getOwnPropertyDescriptor(value, key)!;
+      if ('value' in descriptor) {
+        descriptor.value = _replaceRecur(descriptor.value, recur);
+      }
+      Object.defineProperty(clone, key, descriptor);
+    }
+    return clone;
+  }
+  return value;
+}
